        /// <summary>
        /// Checks whether a path is a subdirectory of another path.
        /// Uses canonicalized full paths to avoid issues with relative paths,
        /// symlinks, and trailing slashes.
        /// </summary>
        /// <param name="parentPath">The potential parent directory path</param>
        /// <param name="childPath">The potential child directory path</param>
        /// <returns>true if childPath is a subdirectory of parentPath</returns>
